mapper.update:

set @num:=#{preOrdernum};


update cm_knowledge_unit a set ordernum=(
    select t.num from(
        select @num:=@num+1 as num,id from cm_knowledge_unit where pid=#{unitid} and courseid=#{courseid} and ordernum>=#{beginOrdernum} and #{endOrdernum}>=ordernum order by ordernum asc
    ) t where t.id=a.id
)where pid=#{unitid} and courseid=#{courseid} and ordernum>=#{beginOrdernum} and #{endOrdernum}>=ordernum;
